#include<bits/stdc++.h>
using namespace std;
bool d(int n){
	for(int i=1;i*i<n;i++){
		for(int j=1;j*j<n;j++){
			if(i*i+j*j==n) return true;
		}
	}return false;
}
int main(){
	int a,b[10001];
	cin>>a;
	for(int i=0;i<a;i++){
		cin>>b[i];
	}for(int i=0;i<a;i++){
		if(d(b[i])){
			cout<<"Yes"<<endl;
		}else{
			cout<<"No"<<endl;	
		}
	}
}
